val double: (Int) -> Int = { it * 2 }
println(double(5))
println(double.invoke(5))

fun <T, R> List<T>.mapFirst(transform: (T) -> R): R? {
    return if (isEmpty()) null else transform(first())
}
println(listOf(3, 1, 4).mapFirst { it * 10 })
println(emptyList<Int>().mapFirst { it * 10 })

fun <A, B, C> compose(f: (A) -> B, g: (B) -> C): (A) -> C {
    return { a -> g(f(a)) }
}
val doubleIt = { x: Int -> x * 2 }
val addTen  = { x: Int -> x + 10 }
val combined = compose(doubleIt, addTen)
println(combined(5))

fun runIfProvided(value: Int, action: ((Int) -> String)?) {
    val result = action?.invoke(value) ?: "no action"
    println(result)
}
runIfProvided(42, { "Got $it" })
runIfProvided(42, null)
